{
  "sentences": [
    {
      "text": "我每天早上七點起床。",
      "pinyin": "Wǒ měitiān zǎoshang qī diǎn qǐchuáng.",
      "pinyin_numeric": "wo3 mei3tian1 zao3shang4 qi1 dian3 qi3chuang2",
      "translation_en": "I get up at seven every morning.",
      "translation_ko": "저는 매일 아침 7시에 일어납니다."
    },
    {
      "text": "他中午十二點吃午餐。",
      "pinyin": "Tā zhōngwǔ shí'èr diǎn chī wǔcān.",
      "pinyin_numeric": "ta1 zhong1wu3 shi2er4 dian3 chi1 wu3can1",
      "translation_en": "He eats lunch at twelve noon.",
      "translation_ko": "그는 낮 12시에 점심을 먹습니다."
    },
    {
      "text": "我們晚上八點看電視。",
      "pinyin": "Wǒmen wǎnshàng bā diǎn kàn diànshì.",
      "pinyin_numeric": "wo3men wan3shang4 ba1 dian3 kan4 dian4shi4",
      "translation_en": "We watch TV at eight in the evening.",
      "translation_ko": "우리는 저녁 8시에 텔레비전을 봅니다."
    },
    {
      "text": "她下午三點上班。",
      "pinyin": "Tā xiàwǔ sān diǎn shàngbān.",
      "pinyin_numeric": "ta1 xia4wu3 san1 dian3 shang4ban1",
      "translation_en": "She goes to work at three in the afternoon.",
      "translation_ko": "그녀는 오후 3시에 출근합니다."
    },
    {
      "text": "我哥哥晚上十一點睡覺。",
      "pinyin": "Wǒ gēge wǎnshàng shíyī diǎn shuìjiào.",
      "pinyin_numeric": "wo3 ge1ge wan3shang4 shi2yi1 dian3 shui4jiao4",
      "translation_en": "My older brother goes to sleep at eleven at night.",
      "translation_ko": "제 오빠는 밤 11시에 잠을 잡니다."
    },
    {
      "text": "他每天下午五點下班。",
      "pinyin": "Tā měitiān xiàwǔ wǔ diǎn xiàbān.",
      "pinyin_numeric": "ta1 mei3tian1 xia4wu3 wu3 dian3 xia4ban1",
      "translation_en": "He gets off work at five every afternoon.",
      "translation_ko": "그는 매일 오후 5시에 퇴근합니다."
    },
    {
      "text": "我們早上九點上課。",
      "pinyin": "Wǒmen zǎoshang jiǔ diǎn shàngkè.",
      "pinyin_numeric": "wo3men zao3shang4 jiu3 dian3 shang4ke4",
      "translation_en": "We have class at nine in the morning.",
      "translation_ko": "우리는 아침 9시에 수업을 듣습니다."
    },
    {
      "text": "她晚上六點洗澡。",
      "pinyin": "Tā wǎnshàng liù diǎn xǐzǎo.",
      "pinyin_numeric": "ta1 wan3shang4 liu4 dian3 xi3zao3",
      "translation_en": "She takes a shower at six in the evening.",
      "translation_ko": "그녀는 저녁 6시에 샤워를 합니다."
    },
    {
      "text": "我弟弟下午四點回家。",
      "pinyin": "Wǒ dìdi xiàwǔ sì diǎn huíjiā.",
      "pinyin_numeric": "wo3 di4di xia4wu3 si4 dian3 hui2jia1",
      "translation_en": "My younger brother goes home at four in the afternoon.",
      "translation_ko": "제 남동생은 오후 4시에 집에 돌아갑니다."
    },
    {
      "text": "他每天早上八點刷牙洗臉。",
      "pinyin": "Tā měitiān zǎoshang bā diǎn shuāyá xǐliǎn.",
      "pinyin_numeric": "ta1 mei3tian1 zao3shang4 ba1 dian3 shua1ya2 xi3lian3",
      "translation_en": "He brushes his teeth and washes his face at eight every morning.",
      "translation_ko": "그는 매일 아침 8시에 이를 닦고 세수를 합니다."
    }
  ]
}
